{"content": """"Mini CLI calculator."""
import argparse
import sys

def format_num(n):
    if n == int(n):
        return str(int(n))
    return str(n)

def main():
    parser = argparse.ArgumentParser(description="Mini CLI calculator")
    subparsers = parser.add_subparsers(dest="command", required=True)

    # add
    parser_add = subparsers.add_parser("add")
    parser_add.add_argument("a", type=float)
    parser_add.add_argument("b", type=float)

    # sub
    parser_sub = subparsers.add_parser("sub")
    parser_sub.add_argument("a", type=float)
    parser_sub.add_argument("b", type=float)

    # mul
    parser_mul = subparsers.add_parser("mul")
    parser_mul.add_argument("a", type=float)
    parser_mul.add_argument("b", type=float)

    # div
    parser_div = subparsers.add_parser("div")
    parser_div.add_argument("a", type=float)
    parser_div.add_argument("b", type=float)

    args = parser.parse_args()

    try:
        if args.command == "add":
            print(format_num(args.a + args.b))
        elif args.command == "sub":
            print(format_num(args.a - args.b))
        elif args.command == "mul":
            print(format_num(args.a * args.b))
        elif args.command == "div":
            if args.b == 0:
                print("Error: Division by zero", file=sys.stderr)
                sys.exit(1)
            print(format_num(args.a / args.b))
    except Exception as e:
        print(f"Error: {e}", file=sys.stderr)
        sys.exit(1)

if __name__ == "__main__":
    main()
